const admin = require\("firebase-admin"\);
require\("dotenv"\).config\(\);
if \(!admin.apps.length\) {
  admin.initializeApp\({ credential: admin.credential.applicationDefault\(\) }\);
}
const db = admin.firestore\(\);

\(async \(\) => {
  // Simulate what the worker does: startAfter is NOT used on first page.
  // Instead it fetches from the beginning and uses isAfterCursor in-memory.
  // Lets check: how many total docs, and how many have created_at > cursor?

  const cursor = "2026-02-24T21:16:49.283236";
  const cursorId = "lch_efcca7a0b2a4";

  // 1. Total docs in launches_v2
  const allSnap = await db.collection\("launches_v2"\).count\(\).get\(\);
  console.log\("Total launches_v2 docs:", allSnap.data\(\).count\);

  // 2. Check docs after cursor date using a simple where
  const afterSnap = await db.collection\("launches_v2"\)
    .where\("created_at", ">", cursor\)
    .limit\(5\)
    .get\(\);
  console.log\("Docs with created_at >", cursor, ":", afterSnap.size\);
  afterSnap.docs.forEach\(d => {
    console.log\("  ", d.id, "created_at:", d.data\(\).created_at, "type:", typeof d.data\(\).created_at\);
  }\);

  // 3. Check what type created_at is on a few recent docs
  const recentSnap = await db.collection\("launches_v2"\)
    .orderBy\("created_at", "desc"\)
    .limit\(3\)
    .get\(\);
  console.log\("\\nMost recent by created_at:"\);
  recentSnap.docs.forEach\(d => {
    const ca = d.data\(\).created_at;
    console.log\("  ", d.id, "created_at:", ca, "type:", typeof ca, "isTimestamp:", ca && ca._seconds !== undefined\);
  }\);

  process.exit\(0\);
}\)\(\);
')

